SELECT function_name
FROM functions
ORDER BY function_name ASC;

SELECT COUNT(data_id) AS total_data_points
   FROM function_data
   WHERE function_id = 123;

SELECT function_name, creation_date
FROM functions
ORDER BY creation_date DESC;

SELECT function_id, COUNT(y_value) as data_points_count
FROM function_data
GROUP BY function_id;
